type Session struct {
	ID          string
	UserID      string
	Preferences map[string]interface{}
	Permissions []string
	CreatedAt   time.Time
	UpdatedAt   time.Time
	ExpiresAt   time.Time
}

type SessionManager struct {
	sessions map[string]*Session
	mu       sync.RWMutex
	dir      string
}

func NewSessionManager(dir string) (*SessionManager, error) {
	if err := os.MkdirAll(dir, 0700); err != nil {
		return nil, fmt.Errorf("failed to create session directory: %w", err)
	}

	sm := &SessionManager{
		sessions: make(map[string]*Session),
		dir:      dir,
	}

	if err := sm.loadSessions(); err != nil {
		return nil, fmt.Errorf("failed to load sessions: %w", err)
	}

	return sm, nil
}

func (sm *SessionManager) CreateSession(userID string, preferences map[string]interface{}, permissions []string) (*Session, error) {
	session := &Session{
		ID:          generateSessionID(),
		UserID:      userID,
		Preferences: preferences,
		Permissions: permissions,
		CreatedAt:   time.Now().UTC(),
		UpdatedAt:   time.Now().UTC(),
		ExpiresAt:   time.Now().UTC().Add(24 * time.Hour),
	}

	sm.mu.Lock()
	sm.sessions[session.ID] = session
	sm.mu.Unlock()

	if err := sm.saveSession(session); err != nil {
		return nil, fmt.Errorf("failed to save session: %w", err)
	}

	return session, nil
}

func (sm *SessionManager) GetSession(sessionID string) (*Session, bool) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()

	session, exists := sm.sessions[sessionID]
	if !exists {
		return nil, false
	}

	if time.Now().UTC().After(session.ExpiresAt) {
		go sm.DeleteSession(sessionID)
		return nil, false
	}

	return session, true
}

func (sm *SessionManager) UpdateSession(sessionID string, preferences map[string]interface{}, permissions []string) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	session, exists := sm.sessions[sessionID]
	if !exists {
		return fmt.Errorf("session not found")
	}

	session.Preferences = preferences
	session.Permissions = permissions
	session.UpdatedAt = time.Now().UTC()

	if err := sm.saveSession(session); err != nil {
		return fmt.Errorf("failed to save session: %w", err)
	}

	return nil
}

func (sm *SessionManager) DeleteSession(sessionID string) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	session, exists := sm.sessions[sessionID]
	if !exists {
		return nil
	}

	delete(sm.sessions, sessionID)
	
	sessionPath := filepath.Join(sm.dir, sessionID+".gob")
	if err := os.Remove(sessionPath); err != nil {
		log.Printf("failed to delete session file: %v", err)
	}

	return nil
}

func (sm *SessionManager) CleanupExpired() {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	now := time.Now().UTC()
	for sessionID, session := range sm.sessions {
		if now.After(session.ExpiresAt) {
			delete(sm.sessions, sessionID)
			sessionPath := filepath.Join(sm.dir, sessionID+".gob")
			os.Remove(sessionPath)
		}
	}
}

func (sm *SessionManager) loadSessions() error {
	files, err := os.ReadDir(sm.dir)
	if err != nil {
		return err
	}

	for _, file := range files {
		if filepath.Ext(file.Name()) == ".gob" {
			session, err := sm.loadSessionFromFile(filepath.Join(sm.dir, file.Name()))
			if err != nil {
				log.Printf("failed to load session %s: %v", file.Name(), err)
				continue
			}
			sm.sessions[session.ID] = session
		}
	}

	return nil
}

func (sm *SessionManager) loadSessionFromFile(path string) (*Session, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	var session Session
	decoder := gob.NewDecoder(file)
	if err := decoder.Decode(&session); err != nil {
		return nil, err
	}

	return &session, nil
}

func (sm *SessionManager) saveSession(session *Session) error {
	path := filepath.Join(sm.dir, session.ID+".gob")
	
	file, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0600)
	if err != nil {
		return err
	}
	defer file.Close()

	encoder := gob.NewEncoder(file)
	encoder.SetEscapeHTML(false)
	
	return encoder.Encode(session)
}

func generateSessionID() string {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		// Fallback to timestamp if crypto/rand fails
		return fmt.Sprintf("%d", time.Now().UnixNano())
	}
	return hex.EncodeToString(bytes)
}

